'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { Shield, Zap, Lock, ArrowRight, BarChart3, Binary } from 'lucide-react';
import { supabase } from '@/lib/supabase';

export default function LandingPage() {
  const [stats, setStats] = useState({ total: 0, solved: 0 });

  useEffect(() => {
    const fetchStats = async () => {
      const { count: total } = await supabase
        .from('legal_documents')
        .select('*', { count: 'exact', head: true });

      const { count: solved } = await supabase
        .from('legal_documents')
        .select('*', { count: 'exact', head: true })
        .eq('status', 'completed');

      setStats({
        total: total || 0,
        solved: solved || 0
      });
    };

    fetchStats();
  }, []);

  return (
    <div className="flex flex-col">
      {/* Hero Section */}
      <section className="relative bg-slate-950 py-24 overflow-hidden">
        {/* Background Gradients */}
        <div className="absolute top-0 right-0 w-1/3 h-full bg-indigo-600/10 blur-[120px] rounded-full -mr-20 -mt-20"></div>
        <div className="absolute bottom-0 left-0 w-1/3 h-full bg-blue-600/10 blur-[120px] rounded-full -ml-20 -mb-20"></div>

        <div className="max-w-7xl mx-auto px-4 relative">
          <div className="text-center max-w-4xl mx-auto">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 text-xs font-bold uppercase tracking-wider mb-8">
              <Shield className="h-3 w-3" /> Government Grade AI
            </div>

            <h1 className="text-5xl md:text-7xl font-extrabold text-white mb-8 tracking-tight leading-[1.1]">
              Automated Legal <span className="text-indigo-500">Classification</span>
            </h1>

            <p className="text-xl text-slate-400 mb-12 leading-relaxed">
              Streamline document processing with our advanced machine learning pipeline.
              Designed for official government use at Kalasalingam Academy.
            </p>

            <div className="flex flex-col sm:flex-row items-center justify-center gap-4 mb-16">
              <Link
                href="/auth/register"
                className="w-full sm:w-auto px-8 py-4 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-bold text-lg transition shadow-lg shadow-indigo-600/20 flex items-center justify-center gap-2 group"
              >
                Get Started <ArrowRight className="h-5 w-5 group-hover:translate-x-1 transition-transform" />
              </Link>
              <Link
                href="/team"
                className="w-full sm:w-auto px-8 py-4 bg-slate-900 border border-slate-800 text-slate-300 rounded-xl font-bold text-lg hover:bg-slate-800 transition"
              >
                Meet the Team
              </Link>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 md:gap-8 bg-slate-900/50 p-8 rounded-3xl border border-white/5 backdrop-blur-md">
              <div className="flex flex-col items-center">
                <div className="text-4xl md:text-5xl font-black text-white mb-2">{stats.total}</div>
                <div className="text-[10px] text-slate-500 uppercase font-black tracking-widest">Cases Processed</div>
              </div>
              <div className="flex flex-col items-center border-x border-white/5">
                <div className="text-4xl md:text-5xl font-black text-emerald-400 mb-2">{stats.solved}</div>
                <div className="text-[10px] text-slate-500 uppercase font-black tracking-widest">AI Solved</div>
              </div>
              <div className="hidden md:flex flex-col items-center">
                <div className="text-4xl md:text-5xl font-black text-amber-400 mb-2">99.8%</div>
                <div className="text-[10px] text-slate-500 uppercase font-black tracking-widest">Accuracy</div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Features Section */}
      <section className="py-24 bg-white">
        <div className="max-w-7xl mx-auto px-4">
          <div className="text-center mb-16">
            <h2 className="text-3xl font-bold text-slate-900 mb-4">Enterprise-Ready Features</h2>
            <div className="w-20 h-1 bg-indigo-600 mx-auto rounded-full"></div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <FeatureCard
              icon={<Zap className="h-6 w-6" />}
              title="Automatic Scanning"
              desc="Extracts text from PDF and DOC documents instantly using advanced OCR engines."
              number="01"
            />
            <FeatureCard
              icon={<Binary className="h-6 w-6" />}
              title="AI Classification"
              desc="Deep learning models categorize cases into Criminal, Civil, Corporate and more."
              number="02"
            />
            <FeatureCard
              icon={<Lock className="h-6 w-6" />}
              title="Secure Storage"
              desc="Role-based access control ensuring sensitive government data remains private."
              number="03"
            />
          </div>
        </div>
      </section>
    </div>
  );
}

function FeatureCard({ icon, title, desc, number }: { icon: any, title: string, desc: string, number: string }) {
  return (
    <div className="p-8 bg-slate-50 rounded-2xl border border-slate-200 hover:border-indigo-200 hover:shadow-xl hover:shadow-indigo-500/5 transition group">
      <div className="flex justify-between items-start mb-6">
        <div className="bg-white p-3 rounded-xl shadow-sm text-indigo-600 group-hover:bg-indigo-600 group-hover:text-white transition">
          {icon}
        </div>
        <span className="text-slate-300 font-black text-2xl tracking-tighter group-hover:text-indigo-200 transition">{number}</span>
      </div>
      <h3 className="text-xl font-bold text-slate-900 mb-3">{title}</h3>
      <p className="text-slate-600 leading-relaxed">{desc}</p>
    </div>
  );
}
